svg.script:

const scoreEl = document.getElementById('score');
const overlay = document.getElementById('overlay');
const startBtn = document.getElementById('start-btn');

const colors = {
    green: { el: document.getElementById('q-green'), freq: 261.63, id: 'green' },
    red: { el: document.getElementById('q-red'), freq: 329.63, id: 'red' },
    yellow: { el: document.getElementById('q-yellow'), freq: 392.00, id: 'yellow' },
    blue: { el: document.getElementById('q-blue'), freq: 493.88, id: 'blue' }
};

let sequence = [];
let userSequence = [];
let score = 0;
let isPlayingSequence = false;
let gameActive = false;

const audioCtx = new (window.AudioContext || window.webkitAudioContext)();

function playTone(freq) {
    const osc = audioCtx.createOscillator();
    const gain = audioCtx.createGain();
    osc.type = 'sine';
    osc.frequency.setValueAtTime(freq, audioCtx.currentTime);
    gain.gain.setValueAtTime(0.5, audioCtx.currentTime);
    gain.gain.exponentialRampToValueAtTime(0.01, audioCtx.currentTime + 0.4);
    osc.connect(gain);
    gain.connect(audioCtx.destination);
    osc.start();
    osc.stop(audioCtx.currentTime + 0.4);
}

function lightUp(colorId) {
    const target = colors[colorId].el;
    const light = target.querySelector('.light');
    light.setAttribute('opacity', '1');
    playTone(colors[colorId].freq);
    setTimeout(() => light.setAttribute('opacity', '0'), 300);
}

async function playSequence() {
    isPlayingSequence = true;
    for (const color of sequence) {
        await new Promise(resolve => {
            lightUp(color);
            setTimeout(resolve, 600);
        });
    }
    isPlayingSequence = false;
}

function nextLevel() {
    userSequence = [];
    const allColors = ['green', 'red', 'yellow', 'blue'];
    sequence.push(allColors[Math.floor(Math.random() * 4)]);
    score++;
    scoreEl.textContent = score;
    playSequence();
}

function handleInput(colorId) {
    if (!gameActive || isPlayingSequence) return;

    lightUp(colorId);
    userSequence.push(colorId);

    const currentStep = userSequence.length - 1;
    if (userSequence[currentStep] !== sequence[currentStep]) {
        gameOver();
        return;
    }

    if (userSequence.length === sequence.length) {
        setTimeout(nextLevel, 1000);
    }
}

function gameOver() {
    gameActive = false;
    overlay.setAttribute('visibility', 'visible');
}

function start() {
    audioCtx.resume();
    score = 0;
    sequence = [];
    userSequence = [];
    scoreEl.textContent = '0';
    gameActive = true;
    overlay.setAttribute('visibility', 'hidden');
    nextLevel();
}

Object.keys(colors).forEach(colorId => {
    colors[colorId].el.addEventListener('click', () => handleInput(colorId));
});

startBtn.addEventListener('click', start);
overlay.addEventListener('click', start);
